#pragma once

#include <vector>
#include <string>

namespace rpi_rt {
  /**
   * The detection result base class, generated by detection logic.
   *
   * Adhere to the Single Responsibility Principle (SRP) and the
   * Open-Closed Principle (OCP) in SOLID.
   */
  class detection_result_t {
    public:
      virtual ~detection_result_t() {}

      /**
       * If a fire is detected.
       */
      virtual bool has_fire() = 0;
      /**
       * Explain the reason for justification.
       */
      virtual std::string explain() = 0;
      /**
       * Provide an optional JPEG image attachment for vision-led detection
       * results.
       *
       * Returns an empty vector if no such data is applicable
       */
      virtual std::vector<uint8_t> jpg_attachment() {
        return {};
      };
  };
}

